INSERT INTO sql_questions
  (database_type, difficulty, question_number, topic, question_text, hint, expected_sql)
VALUES
  ('postgres', 'beginner', 1, 'SELECT Basics', 'Write a query to select all columns and all rows from the employees table.', 'Use SELECT * FROM table_name;', 'SELECT * FROM employees;'),
  ('postgres', 'beginner', 2, 'SELECT Columns', 'Write a query to select only the name and department columns from the employees table.', 'List the column names separated by commas after SELECT.', 'SELECT name, department FROM employees;'),
  ('postgres', 'beginner', 3, 'WHERE Clause', 'Write a query to fetch all employees who work in the ''Engineering'' department.', 'Use WHERE department = ''Engineering''', 'SELECT * FROM employees WHERE department = ''Engineering'';'),
  ('postgres', 'beginner', 4, 'WHERE with Numbers', 'Write a query to fetch all employees with a salary greater than 90000.', 'Use WHERE salary > 90000', 'SELECT * FROM employees WHERE salary > 90000;'),
  ('postgres', 'beginner', 5, 'ORDER BY', 'Write a query to select all employees ordered by their salary in descending order.', 'Use ORDER BY salary DESC', 'SELECT * FROM employees ORDER BY salary DESC;'),
  ('postgres', 'beginner', 6, 'ORDER BY ASC', 'Write a query to select all employees ordered by name in ascending (alphabetical) order.', 'Use ORDER BY name ASC', 'SELECT * FROM employees ORDER BY name ASC;'),
  ('postgres', 'beginner', 7, 'LIMIT', 'Write a query to fetch the top 3 employees ordered by salary descending.', 'Use ORDER BY salary DESC LIMIT 3', 'SELECT * FROM employees ORDER BY salary DESC LIMIT 3;'),
  ('postgres', 'beginner', 8, 'DISTINCT', 'Write a query to get a list of all unique departments from the employees table.', 'Use SELECT DISTINCT column_name', 'SELECT DISTINCT department FROM employees;'),
  ('postgres', 'beginner', 9, 'COUNT', 'Write a query to count the total number of employees.', 'Use COUNT(*) or COUNT(id)', 'SELECT COUNT(*) FROM employees;'),
  ('postgres', 'beginner', 10, 'Aggregate Functions', 'Write a query to find the maximum salary in the employees table.', 'Use SELECT MAX(salary)', 'SELECT MAX(salary) FROM employees;'),
  ('postgres', 'beginner', 11, 'Aggregate Functions', 'Write a query to find the minimum salary in the employees table.', 'Use SELECT MIN(salary)', 'SELECT MIN(salary) FROM employees;'),
  ('postgres', 'beginner', 12, 'Aggregate Functions', 'Write a query to find the average salary of all employees.', 'Use SELECT AVG(salary)', 'SELECT AVG(salary) FROM employees;'),
  ('postgres', 'beginner', 13, 'Aggregate Functions', 'Write a query to calculate the total (SUM) of all employee salaries.', 'Use SELECT SUM(salary)', 'SELECT SUM(salary) FROM employees;'),
  ('postgres', 'beginner', 14, 'WHERE with AND', 'Write a query to fetch employees in the ''Engineering'' department with salary greater than 95000.', 'Use WHERE department = ''...'' AND salary > ...', 'SELECT * FROM employees WHERE department = ''Engineering'' AND salary > 95000;'),
  ('postgres', 'beginner', 15, 'WHERE with OR', 'Write a query to fetch employees from either ''HR'' or ''Finance'' departments.', 'Use WHERE department = ''HR'' OR department = ''Finance''', 'SELECT * FROM employees WHERE department = ''HR'' OR department = ''Finance'';'),
  ('postgres', 'beginner', 16, 'CREATE TABLE', 'Create a new table called ''departments'' with columns: id (SERIAL PRIMARY KEY) and dept_name (VARCHAR(100)).', 'In PostgreSQL, use SERIAL instead of AUTO_INCREMENT', 'CREATE TABLE departments (id SERIAL PRIMARY KEY, dept_name VARCHAR(100));'),
  ('postgres', 'beginner', 17, 'INSERT with RETURNING', 'Insert a new employee: name=''Test User'', department=''Finance'', salary=75000, hire_date=''2024-01-01''. Return the id of the inserted row.', 'In PostgreSQL, add RETURNING id at the end of INSERT', 'INSERT INTO employees (name, department, salary, hire_date) VALUES (''Test User'', ''Finance'', 75000, ''2024-01-01'') RETURNING id;'),
  ('postgres', 'beginner', 18, 'UPDATE', 'Update the salary of the employee named ''Bob Smith'' to 80000.', 'Use UPDATE employees SET salary = 80000 WHERE name = ''Bob Smith''', 'UPDATE employees SET salary = 80000 WHERE name = ''Bob Smith'';'),
  ('postgres', 'beginner', 19, 'DELETE', 'Delete all employees from the HR department.', 'Use DELETE FROM employees WHERE department = ''HR''', 'DELETE FROM employees WHERE department = ''HR'';'),
  ('postgres', 'beginner', 20, 'List Tables', 'Write a query to list all tables in your current schema using information_schema.', 'In PostgreSQL, use SELECT table_name FROM information_schema.tables WHERE table_schema = ''public''', 'SELECT table_name FROM information_schema.tables WHERE table_schema = ''public'';'),
  ('postgres', 'beginner', 21, 'Describe Table', 'Write a query to show the column names and data types of the employees table using information_schema.', 'Use SELECT column_name, data_type FROM information_schema.columns WHERE table_name = ''employees''', 'SELECT column_name, data_type FROM information_schema.columns WHERE table_name = ''employees'';'),
  ('postgres', 'beginner', 22, 'ALTER TABLE', 'Add a new column ''email'' of type VARCHAR(200) to the employees table.', 'Use ALTER TABLE employees ADD COLUMN email VARCHAR(200)', 'ALTER TABLE employees ADD COLUMN email VARCHAR(200);'),
  ('postgres', 'beginner', 23, 'SELECT with ALIAS', 'Write a query to select employee name as ''Employee Name'' and salary as ''Monthly Salary'' from employees.', 'Use column AS "alias name" (double quotes in PostgreSQL)', 'SELECT name AS "Employee Name", salary AS "Monthly Salary" FROM employees;'),
  ('postgres', 'beginner', 24, 'NULL Checks', 'Write a query to find all employees where the department is NULL.', 'Use WHERE department IS NULL', 'SELECT * FROM employees WHERE department IS NULL;'),
  ('postgres', 'beginner', 25, 'NOT NULL', 'Write a query to find all employees where department is NOT NULL.', 'Use WHERE department IS NOT NULL', 'SELECT * FROM employees WHERE department IS NOT NULL;'),
  ('postgres', 'beginner', 26, 'SELECT with Calculation', 'Write a query to show each employee''s name and their annual salary (multiply monthly salary by 12).', 'Use salary * 12 in your SELECT', 'SELECT name, salary * 12 AS annual_salary FROM employees;'),
  ('postgres', 'beginner', 27, 'ILIKE Pattern', 'Write a query to find all employees whose name starts with ''a'' (case-insensitive) using ILIKE.', 'Use WHERE name ILIKE ''a%'' — PostgreSQL''s case-insensitive LIKE', 'SELECT * FROM employees WHERE name ILIKE ''a%'';'),
  ('postgres', 'beginner', 28, 'Products Table', 'Write a query to select all products with a price less than 100.', 'Use SELECT * FROM products WHERE price < 100', 'SELECT * FROM products WHERE price < 100;'),
  ('postgres', 'beginner', 29, 'GROUP BY', 'Write a query to count the number of employees in each department.', 'Use GROUP BY department with COUNT(*)', 'SELECT department, COUNT(*) AS employee_count FROM employees GROUP BY department;'),
  ('postgres', 'beginner', 30, 'ORDER BY Multiple', 'Write a query to select all employees ordered first by department (ascending) then by salary (descending).', 'Use ORDER BY department ASC, salary DESC', 'SELECT * FROM employees ORDER BY department ASC, salary DESC;'),
  ('postgres', 'moderate', 31, 'INNER JOIN', 'Write a query to join the orders table with the employees table to show each order''s employee name and total price.', 'Use INNER JOIN ... ON orders.employee_id = employees.id', 'SELECT e.name, o.total_price FROM orders o INNER JOIN employees e ON o.employee_id = e.id;'),
  ('postgres', 'moderate', 32, 'JOIN with Products', 'Write a query to show each order with the product name and quantity ordered.', 'JOIN orders with products on product_id', 'SELECT p.name AS product_name, o.quantity FROM orders o INNER JOIN products p ON o.product_id = p.id;'),
  ('postgres', 'moderate', 33, 'LEFT JOIN', 'Write a query using LEFT JOIN to show all employees and their orders (including employees with no orders).', 'Use LEFT JOIN orders ON employees.id = orders.employee_id', 'SELECT e.name, o.total_price FROM employees e LEFT JOIN orders o ON e.id = o.employee_id;'),
  ('postgres', 'moderate', 34, 'GROUP BY with HAVING', 'Write a query to find departments where the average salary is greater than 80000.', 'Use GROUP BY department HAVING AVG(salary) > 80000', 'SELECT department, AVG(salary) AS avg_salary FROM employees GROUP BY department HAVING AVG(salary) > 80000;'),
  ('postgres', 'moderate', 35, 'Subquery', 'Write a query to find all employees who earn more than the average salary.', 'Use WHERE salary > (SELECT AVG(salary) FROM employees)', 'SELECT * FROM employees WHERE salary > (SELECT AVG(salary) FROM employees);'),
  ('postgres', 'moderate', 36, 'IN Clause', 'Write a query to find employees in the ''Engineering'', ''Finance'', or ''Marketing'' departments using IN.', 'Use WHERE department IN (''Engineering'', ''Finance'', ''Marketing'')', 'SELECT * FROM employees WHERE department IN (''Engineering'', ''Finance'', ''Marketing'');'),
  ('postgres', 'moderate', 37, 'NOT IN', 'Write a query to find all products not in the ''Electronics'' category.', 'Use WHERE category NOT IN (''Electronics'')', 'SELECT * FROM products WHERE category NOT IN (''Electronics'');'),
  ('postgres', 'moderate', 38, 'BETWEEN', 'Write a query to find employees with a salary between 70000 and 100000.', 'Use WHERE salary BETWEEN 70000 AND 100000', 'SELECT * FROM employees WHERE salary BETWEEN 70000 AND 100000;'),
  ('postgres', 'moderate', 39, 'ILIKE Pattern', 'Write a query to find all products whose name contains ''desk'' (case-insensitive).', 'Use WHERE name ILIKE ''%desk%''', 'SELECT * FROM products WHERE name ILIKE ''%desk%'';'),
  ('postgres', 'moderate', 40, 'Three-Table JOIN', 'Write a query joining employees, orders, and products to show the employee name, product name, and total price for each order.', 'JOIN orders with employees and products', 'SELECT e.name AS employee, p.name AS product, o.total_price FROM orders o JOIN employees e ON o.employee_id = e.id JOIN products p ON o.product_id = p.id;'),
  ('postgres', 'moderate', 41, 'Aggregate with JOIN', 'Write a query to find the total amount spent by each employee (sum of their orders).', 'JOIN orders with employees, GROUP BY employee name, SUM total_price', 'SELECT e.name, SUM(o.total_price) AS total_spent FROM employees e JOIN orders o ON e.id = o.employee_id GROUP BY e.name;'),
  ('postgres', 'moderate', 42, 'Subquery with IN', 'Write a query to find all employees who have placed at least one order, using a subquery.', 'Use WHERE id IN (SELECT employee_id FROM orders)', 'SELECT * FROM employees WHERE id IN (SELECT DISTINCT employee_id FROM orders);'),
  ('postgres', 'moderate', 43, 'DATE Functions', 'Write a query to find all employees hired in the year 2020 using EXTRACT.', 'Use EXTRACT(YEAR FROM hire_date) = 2020', 'SELECT * FROM employees WHERE EXTRACT(YEAR FROM hire_date) = 2020;'),
  ('postgres', 'moderate', 44, 'String Functions', 'Write a query to display each employee''s name in uppercase using PostgreSQL''s UPPER function.', 'Use UPPER(name)', 'SELECT UPPER(name) AS name_upper FROM employees;'),
  ('postgres', 'moderate', 45, 'CONCAT / ||', 'Write a query to combine the employee name and department using the PostgreSQL string concatenation operator ||.', 'Use name || '' - '' || department', 'SELECT name || '' - '' || department AS employee_info FROM employees;'),
  ('postgres', 'moderate', 46, 'CASE Expression', 'Write a query to categorize employees as ''High'' (salary >= 90000), ''Mid'' (salary >= 70000), or ''Low'' otherwise.', 'Use CASE WHEN salary >= 90000 THEN ''High'' ... END', 'SELECT name, salary, CASE WHEN salary >= 90000 THEN ''High'' WHEN salary >= 70000 THEN ''Mid'' ELSE ''Low'' END AS salary_band FROM employees;'),
  ('postgres', 'moderate', 47, 'EXISTS', 'Write a query to find all products that appear in at least one order, using EXISTS.', 'Use WHERE EXISTS (SELECT 1 FROM orders WHERE orders.product_id = products.id)', 'SELECT * FROM products WHERE EXISTS (SELECT 1 FROM orders WHERE orders.product_id = products.id);'),
  ('postgres', 'moderate', 48, 'ROUND', 'Write a query to show the average salary of each department, rounded to 2 decimal places.', 'Use ROUND(AVG(salary)::numeric, 2) in PostgreSQL', 'SELECT department, ROUND(AVG(salary)::numeric, 2) AS avg_salary FROM employees GROUP BY department;'),
  ('postgres', 'moderate', 49, 'ORDER BY with LIMIT', 'Write a query to find the top 5 most expensive products.', 'Use ORDER BY price DESC LIMIT 5', 'SELECT * FROM products ORDER BY price DESC LIMIT 5;'),
  ('postgres', 'moderate', 50, 'Multi-column GROUP BY', 'Write a query to count orders grouped by employee_id and the year extracted from order_date.', 'Use GROUP BY employee_id, EXTRACT(YEAR FROM order_date)', 'SELECT employee_id, EXTRACT(YEAR FROM order_date) AS order_year, COUNT(*) AS order_count FROM orders GROUP BY employee_id, EXTRACT(YEAR FROM order_date);'),
  ('postgres', 'master', 51, 'Window Functions - ROW_NUMBER', 'Write a query using ROW_NUMBER() to rank employees within each department by salary (highest first).', 'Use ROW_NUMBER() OVER (PARTITION BY department ORDER BY salary DESC)', 'SELECT name, department, salary, ROW_NUMBER() OVER (PARTITION BY department ORDER BY salary DESC) AS row_num FROM employees;'),
  ('postgres', 'master', 52, 'Window Functions - RANK', 'Write a query using RANK() to rank all employees by salary (highest first).', 'Use RANK() OVER (ORDER BY salary DESC)', 'SELECT name, salary, RANK() OVER (ORDER BY salary DESC) AS salary_rank FROM employees;'),
  ('postgres', 'master', 53, 'Window Functions - DENSE_RANK', 'Write a query using DENSE_RANK() to rank employees by salary without gaps in ranking.', 'Use DENSE_RANK() OVER (ORDER BY salary DESC)', 'SELECT name, salary, DENSE_RANK() OVER (ORDER BY salary DESC) AS dense_rank FROM employees;'),
  ('postgres', 'master', 54, 'Window Functions - LAG', 'Write a query using LAG() to show each employee''s salary and the previous employee''s salary ordered by hire_date.', 'Use LAG(salary) OVER (ORDER BY hire_date)', 'SELECT name, hire_date, salary, LAG(salary) OVER (ORDER BY hire_date) AS prev_salary FROM employees;'),
  ('postgres', 'master', 55, 'Window Functions - LEAD', 'Write a query using LEAD() to show each employee''s salary and the next employee''s salary ordered by hire_date.', 'Use LEAD(salary) OVER (ORDER BY hire_date)', 'SELECT name, hire_date, salary, LEAD(salary) OVER (ORDER BY hire_date) AS next_salary FROM employees;'),
  ('postgres', 'master', 56, 'CTE (WITH clause)', 'Write a query using a CTE to find the top earner in each department.', 'Use WITH ranked AS (SELECT ..., ROW_NUMBER() OVER ...) SELECT * FROM ranked WHERE rn = 1', 'WITH ranked AS (SELECT name, department, salary, ROW_NUMBER() OVER (PARTITION BY department ORDER BY salary DESC) AS rn FROM employees) SELECT name, department, salary FROM ranked WHERE rn = 1;'),
  ('postgres', 'master', 57, 'CREATE VIEW', 'Create a view called ''high_earners'' that shows all employees with salary > 90000.', 'Use CREATE OR REPLACE VIEW view_name AS SELECT ...', 'CREATE OR REPLACE VIEW high_earners AS SELECT * FROM employees WHERE salary > 90000;'),
  ('postgres', 'master', 58, 'CREATE INDEX', 'Create an index named ''idx_dept'' on the department column of the employees table.', 'Use CREATE INDEX idx_dept ON employees(department)', 'CREATE INDEX IF NOT EXISTS idx_dept ON employees(department);'),
  ('postgres', 'master', 59, 'List Indexes (pg_indexes)', 'Write a query to show all indexes on the employees table using pg_indexes.', 'Use SELECT * FROM pg_indexes WHERE tablename = ''employees''', 'SELECT indexname, indexdef FROM pg_indexes WHERE tablename = ''employees'';'),
  ('postgres', 'master', 60, 'Recursive CTE', 'Write a query using a recursive CTE to generate a series of numbers from 1 to 5.', 'Use WITH RECURSIVE cte AS (SELECT 1 AS n UNION ALL SELECT n+1 FROM cte WHERE n < 5)', 'WITH RECURSIVE nums AS (SELECT 1 AS n UNION ALL SELECT n + 1 FROM nums WHERE n < 5) SELECT n FROM nums;'),
  ('postgres', 'master', 61, 'UPDATE with RETURNING', 'Update the salary of employee named ''Frank Wilson'' to 82000 and return the updated row.', 'Use UPDATE ... SET ... WHERE ... RETURNING *', 'UPDATE employees SET salary = 82000 WHERE name = ''Frank Wilson'' RETURNING *;'),
  ('postgres', 'master', 62, 'NTILE Window Function', 'Write a query using NTILE(4) to divide employees into 4 salary quartiles.', 'Use NTILE(4) OVER (ORDER BY salary)', 'SELECT name, salary, NTILE(4) OVER (ORDER BY salary) AS quartile FROM employees;'),
  ('postgres', 'master', 63, 'Running Total', 'Write a query to calculate a running total of salaries ordered by hire_date.', 'Use SUM(salary) OVER (ORDER BY hire_date ROWS UNBOUNDED PRECEDING)', 'SELECT name, hire_date, salary, SUM(salary) OVER (ORDER BY hire_date ROWS UNBOUNDED PRECEDING) AS running_total FROM employees;'),
  ('postgres', 'master', 64, 'GENERATE_SERIES', 'Write a query using generate_series() to produce a list of dates for the first 7 days of January 2024.', 'Use generate_series(''2024-01-01''::date, ''2024-01-07''::date, ''1 day''::interval)', 'SELECT generate_series(''2024-01-01''::date, ''2024-01-07''::date, ''1 day''::interval) AS day;'),
  ('postgres', 'master', 65, 'JSON Functions', 'Write a query to select all employee names and convert the result to a JSON array using json_agg.', 'Use SELECT json_agg(name) FROM employees', 'SELECT json_agg(name) AS employee_names FROM employees;');
